#include <stdio.h>
#include <string.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    char s[105];
    while(T--){
        scanf("%s",s);
        int n=strlen(s);
        for(int i=0;i<n;i++){
            putchar(s[i]);
            if(i!=n-1) putchar('-');
        }
        if(T) putchar('\n');
    }
    return 0;
}

